-- 약관 관리 테이블
CREATE TABLE IF NOT EXISTS terms (
  id          UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  type        TEXT        NOT NULL CHECK (type IN ('service','privacy','location','marketing')),
  title       TEXT        NOT NULL,
  content     TEXT        NOT NULL,
  version     TEXT        NOT NULL DEFAULT '1.0',
  is_active   BOOLEAN     NOT NULL DEFAULT TRUE,
  effective_date DATE     NOT NULL DEFAULT CURRENT_DATE,
  created_at  TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at  TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE UNIQUE INDEX IF NOT EXISTS terms_type_unique ON terms(type);

ALTER TABLE terms ENABLE ROW LEVEL SECURITY;
CREATE POLICY "public read"  ON terms FOR SELECT USING (true);
CREATE POLICY "service write" ON terms FOR ALL USING (true);

-- 초기 약관 데이터
INSERT INTO terms (type, title, version, effective_date, content) VALUES

('service', '이용약관', '1.0', '2024-01-01', E'## 제1조 (목적)\n본 약관은 금단앱(이하 "서비스")이 제공하는 검단신도시 커뮤니티 서비스의 이용에 관한 조건 및 절차를 규정함을 목적으로 합니다.\n\n## 제2조 (정의)\n① "서비스"란 검단신도시 주민을 위한 커뮤니티, 상가정보, 교통, 부동산 정보 등을 제공하는 플랫폼을 말합니다.\n② "이용자"란 본 약관에 동의하고 서비스를 이용하는 자를 말합니다.\n③ "게시물"이란 이용자가 서비스에 업로드한 텍스트, 이미지 등 모든 콘텐츠를 말합니다.\n\n## 제3조 (이용 자격)\n① 만 14세 이상이면 누구나 서비스를 이용할 수 있습니다.\n② 검단신도시 거주자가 아닌 경우에도 서비스 이용이 가능하나, 일부 기능은 거주 지역 확인이 필요할 수 있습니다.\n③ 운영자는 부적절한 사용이 확인된 이용자의 계정을 정지하거나 삭제할 수 있습니다.\n\n## 제4조 (금지 행위)\n이용자는 다음 행위를 하여서는 안 됩니다.\n① 타인의 개인정보 무단 수집, 저장 또는 게시하는 행위\n② 음란, 폭력적, 혐오적 게시물을 작성하거나 유포하는 행위\n③ 광고, 홍보 목적의 스팸성 게시물을 반복적으로 작성하는 행위\n④ 타인을 비방하거나 명예를 훼손하는 행위\n⑤ 불법 정보를 게시하거나 유포하는 행위\n⑥ 서비스 운영 시스템을 방해하는 행위\n⑦ 다른 이용자의 ID를 도용하는 행위\n⑧ 저작권 등 지식재산권을 침해하는 행위\n\n## 제5조 (게시물 관리)\n① 이용자가 작성한 게시물의 저작권은 이용자에게 있습니다.\n② 이용자는 서비스 내 게시물 업로드 시 운영자에게 서비스 운영 목적 범위 내에서의 이용을 허락합니다.\n③ 운영자는 제4조의 금지 행위에 해당하는 게시물을 사전 통보 없이 삭제할 수 있습니다.\n④ 삭제된 게시물은 복구되지 않으며, 이에 대해 운영자는 책임을 지지 않습니다.\n\n## 제6조 (서비스 변경 및 중단)\n① 운영자는 서비스 개선, 시스템 점검 등의 사유로 사전 공지 후 서비스를 일시 중단하거나 변경할 수 있습니다.\n② 긴급한 경우 사전 공지 없이 서비스를 중단할 수 있으며, 이 경우 사후에 공지합니다.\n\n## 제7조 (면책 조항)\n① 서비스는 이용자가 게시한 정보의 정확성, 신뢰성에 대해 보장하지 않습니다.\n② 천재지변, 시스템 장애, 해킹 등 불가항력으로 인한 서비스 중단에 대해 책임을 지지 않습니다.\n③ 이용자 간의 거래, 분쟁에 대해 운영자는 개입하지 않으며 책임을 지지 않습니다.\n\n## 제8조 (약관의 변경)\n① 운영자는 합리적인 사유가 있는 경우 약관을 변경할 수 있습니다.\n② 변경 시 시행일 7일 전 앱 내 공지를 통해 안내합니다.\n③ 이용자가 변경 후에도 계속 서비스를 이용하면 변경된 약관에 동의한 것으로 간주합니다.\n\n## 부칙\n본 약관은 2024년 1월 1일부터 시행합니다.'),

('privacy', '개인정보처리방침', '1.0', '2024-01-01', E'금단앱(이하 "서비스")은 이용자의 개인정보를 소중히 여기며, 「개인정보 보호법」을 준수합니다.\n\n## 1. 수집하는 개인정보 항목\n서비스 가입 및 이용 과정에서 아래와 같이 개인정보를 수집합니다.\n\n[필수 항목]\n• 닉네임\n• 거주 동(洞) 정보\n• 서비스 이용 기록, 접속 로그\n\n[선택 항목]\n• 프로필 이미지\n• 휴대폰 번호(본인 인증 시 사용 후 미저장)\n\n## 2. 개인정보 수집 목적\n• 커뮤니티 서비스 제공 및 회원 관리\n• 이용자 식별 및 부정 이용 방지\n• 서비스 품질 개선 및 맞춤형 정보 제공\n• 이벤트 및 공지 안내(동의한 경우에 한함)\n\n## 3. 개인정보 보유 및 이용 기간\n• 원칙: 회원 탈퇴 시 즉시 파기\n• 예외: 관련 법령에 따라 보존이 필요한 경우\n  - 계약 또는 청약철회 기록: 5년 (전자상거래법)\n  - 소비자 불만 처리 기록: 3년 (전자상거래법)\n  - 접속 로그: 3개월 (통신비밀보호법)\n\n## 4. 개인정보 제3자 제공\n이용자의 개인정보를 원칙적으로 제3자에게 제공하지 않습니다. 단, 다음의 경우 예외입니다.\n• 이용자가 사전에 동의한 경우\n• 법령에 의한 경우(수사기관의 적법한 요청 등)\n\n## 5. 개인정보 처리 위탁\n서비스 향상을 위해 아래와 같이 처리 업무를 위탁할 수 있습니다.\n• Supabase Inc. : 데이터베이스 및 인증 서비스\n• Vercel Inc. : 서비스 호스팅\n위탁 계약 시 개인정보 보호 관련 사항을 계약서에 명시합니다.\n\n## 6. 개인정보 파기 절차 및 방법\n• 전자 파일: 복구 불가능한 방법으로 영구 삭제\n• 출력물: 분쇄기를 이용하여 파기\n\n## 7. 이용자의 권리와 행사 방법\n이용자는 언제든지 다음의 권리를 행사할 수 있습니다.\n• 개인정보 열람 요청\n• 오류 정정 또는 삭제 요청\n• 처리 정지 요청\n• 회원 탈퇴(앱 내 마이페이지 > 설정 > 회원 탈퇴)\n\n## 8. 개인정보 보호책임자\n• 담당: 금단앱 운영팀\n• 문의: 앱 내 문의하기 기능 이용\n\n## 9. 개인정보 처리방침 변경\n이 개인정보처리방침은 시행일로부터 적용되며, 법령 및 방침에 따른 변경 내용의 추가, 삭제 및 정정이 있는 경우에는 변경 7일 전부터 공지합니다.\n\n## 부칙\n본 방침은 2024년 1월 1일부터 시행합니다.'),

('location', '위치기반 서비스 이용약관', '1.0', '2024-01-01', E'## 제1조 (목적)\n본 약관은 금단앱(이하 "서비스")이 위치기반서비스사업자로서 이용자의 위치정보를 이용하여 제공하는 서비스와 관련하여, 「위치정보의 보호 및 이용 등에 관한 법률」에 의거한 위치기반 서비스의 제공에 관한 사항을 규정함을 목적으로 합니다.\n\n## 제2조 (위치정보 수집)\n[수집 항목]\n• GPS 기반 현재 위치 (위도, 경도)\n\n[수집 방법]\n• 서비스 이용 시 이용자 기기의 위치정보 기능을 통해 실시간 수집\n• 위치정보는 서버에 저장되지 않으며 기기 내에서만 처리됩니다.\n\n## 제3조 (위치기반 서비스의 종류 및 이용 목적)\n① 주변 버스 정류장 검색 및 실시간 도착 정보 제공\n② 인근 지하철역 및 도착 정보 제공\n③ 주변 상가, 편의시설, 가볼만한 곳 거리 정보 제공\n④ 주변 주유소 가격 정보 제공\n\n## 제4조 (위치정보 보유 기간)\n수집된 위치정보는 서비스 제공 목적 달성 후 즉시 파기합니다. 서비스는 이용자의 위치정보를 서버에 보관하지 않습니다.\n\n## 제5조 (위치정보 제3자 제공)\n수집된 위치정보는 제3자에게 제공하지 않습니다. 단, 이용자의 사전 동의가 있거나 법령에 의한 경우 예외입니다.\n\n## 제6조 (이용자의 권리)\n① 이용자는 위치정보 이용·제공에 대한 동의를 언제든지 철회할 수 있습니다.\n② 동의 철회는 기기 설정(설정 > 개인정보 보호 > 위치)에서 위치 접근 권한을 거부함으로써 가능합니다.\n③ 동의를 철회하더라도 기본 서비스 이용은 가능하나, 위치기반 기능(주변 정류장 등)은 제한될 수 있습니다.\n\n## 제7조 (위치정보 관리책임자)\n• 담당: 금단앱 운영팀\n• 문의: 앱 내 문의하기 기능 이용\n\n## 부칙\n본 약관은 2024년 1월 1일부터 시행합니다.'),

('marketing', '마케팅 정보 수신 동의', '1.0', '2024-01-01', E'## 마케팅 정보 수신 동의 (선택사항)\n본 동의는 선택사항으로, 동의하지 않아도 기본 서비스 이용에 제한이 없습니다.\n\n## 수신 동의 목적\n금단앱 운영팀에서 제공하는 다음의 마케팅 및 홍보 정보를 수신하는 데 동의합니다.\n• 검단신도시 내 새로운 상가·입점 소식 안내\n• 앱 내 쿠폰 및 혜택 정보 발송\n• 이벤트, 프로모션 안내\n• 서비스 업데이트 및 신규 기능 소개\n\n## 수신 방법\n• 앱 푸시 알림\n\n## 보유 및 이용 기간\n• 동의 철회 시까지 또는 서비스 탈퇴 시까지\n\n## 동의 철회 방법\n마케팅 정보 수신을 원하지 않을 경우 언제든지 동의를 철회할 수 있습니다.\n• 앱 내: 마이페이지 > 설정 > 알림 설정에서 마케팅 알림 해제\n• 동의를 철회하더라도 서비스 이용 관련 필수 알림(공지, 이용제한 등)은 계속 발송될 수 있습니다.')

ON CONFLICT (type) DO NOTHING;
